INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.5.153','cb','cb.adi.5','ЧБ Ади 5.153',153,'কত দিন থাকি’ তুমি অনেক দেখিবা ।
এ সব আখ্যান এবে কারে না কহিবা” ॥১৫৩॥','ката дина тха̄ки’ туми анека декхиба
э саба а̄кхйа̄на эбе ка̄ре на̄ кахиба̄’',NULL,NULL),('cb.adi.5.154','cb','cb.adi.5','ЧБ Ади 5.154',154,'হেনমতে ব্রাহ্মণেরে শ্রীগৌরসুন্দর ।
কৃপা করি’ আশ্বাসিয়া গেলা নিজ-ঘর ॥১৫৪॥','хена-мате бра̄хман̣ере ш́рӣ-гаурасундара
кр̣па̄ кари’ а̄ш́ва̄сийа̄ гела̄ ниджа-гхара',NULL,NULL),('cb.adi.5.155','cb','cb.adi.5','ЧБ Ади 5.155',155,'পূর্ব্ববৎ শুইয়া থাকিলা শিশু-ভাবে ।
যোগনিদ্রা-প্রভাবে কেহ নাহি জাগে ॥১৫৫॥','пӯрвават ш́уийа̄ тха̄кила̄ ш́иш́у-бха̄ве
йога-нидра̄-прабха̄ве кеха на̄хи джа̄ге',NULL,NULL),('cb.adi.5.156','cb','cb.adi.5','ЧБ Ади 5.156',156,'অপূর্ব্ব প্রকাশ দেখি’ সেই বিপ্রবর ।
আনন্দে পূর্ণিত হৈল সর্ব্ব-কলেবর ॥১৫৬॥','апӯрва прака̄ш́а декхи’ сеи випра-вара
а̄нанде пурнита хаила сарва-калевара',NULL,NULL),('cb.adi.5.157','cb','cb.adi.5','ЧБ Ади 5.157',157,'সর্ব্ব-অঙ্গে সেই অন্ন করিয়া লেপন ।
কান্দিতে কান্দিতে বিপ্র করেন ভোজন ॥১৫৭॥','сарва-ан̇ге сеи анна карийа̄ лепана
ка̄ндите ка̄ндите випра карена бходжана',NULL,NULL),('cb.adi.5.158','cb','cb.adi.5','ЧБ Ади 5.158',158,'নাচে, গায়, হাসে, বিপ্র করয়ে হুঙ্কার ।
‘জয় বালগোপাল’ বোলয়ে বারবার ॥১৫৮॥','на̄че, га̄йа, ха̄се, випра карайе хун̇ка̄ра
‘джайа ба̄ла-гопа̄ла’ болайе ба̄ра-ба̄ра',NULL,NULL),('cb.adi.5.159','cb','cb.adi.5','ЧБ Ади 5.159',159,'বিপ্রের হুঙ্কারে সবে পাইলা চেতন ।
আপনা সম্বরি’ বিপ্র কৈলা আচমন ॥১৫৯॥','випрера хун̇ка̄ре сабе па̄ила̄ четана
а̄пана̄ самбари’ випра каила а̄чамана',NULL,NULL),('cb.adi.5.160','cb','cb.adi.5','ЧБ Ади 5.160',160,'নির্ব্বিঘ্নে ভোজন করেন বিপ্রবর ।
দেখি’ সবে সন্তোষ হইলা বহুতর ॥১৬০॥','декхи’ сабе сантош̣а хаила бахутара',NULL,NULL),('cb.adi.5.161','cb','cb.adi.5','ЧБ Ади 5.161',161,'সবারে কহিতে মনে চিন্তয়ে ব্রাহ্মণ ।
“ঈশ্বর চিনিয়া সবে পাউক মোচন ॥১৬১॥','саба̄ре кахите мане чинтайе бра̄хман̣а
‘ӣш́вара чинийа̄ сабе па̄ука мочана',NULL,NULL),('cb.adi.5.162','cb','cb.adi.5','ЧБ Ади 5.162',162,'ব্রহ্মা শিব যাঁহার নিমিত্ত কাম্য করে ।
হেন-প্রভু অবতরি’ আছে বিপ্র-ঘরে ॥১৬২॥','брахма̄ ш́ива йа̄н̇ха̄ра нимитта ка̄мйа каре
хена-прабху аватари’ а̄чхе випра-гхаре',NULL,NULL),('cb.adi.5.163','cb','cb.adi.5','ЧБ Ади 5.163',163,'সে প্রভুরে লোক-সব করে শিশু-জ্ঞান ।
কথা কহি,—সবেই পাউক পরিত্রাণ” ॥১৬৩॥','се прабхура лока-саба каре ш́иш́у-джн̃а̄на
катха̄ кахи, — сабеи па̄ука паритра̄н̣а',NULL,NULL),('cb.adi.5.164','cb','cb.adi.5','ЧБ Ади 5.164',164,'‘প্রভু করিয়াছে নিবারণ’—এই ভয়ে ।
আজ্ঞা-ভঙ্গ-ভয়ে বিপ্র কারে নাহি কহে ॥১৬৪॥','‘прабху карийа̄чхе нива̄ран̣а’ — эи бхайе
а̄джн̃а̄-бхан̇га-бхайе випра ка̄ре на̄хи кахе',NULL,NULL),('cb.adi.5.165','cb','cb.adi.5','ЧБ Ади 5.165',165,'চিনিয়া ঈশ্বরে বিপ্র সেই নবদ্বীপে ।
রহিলেন গুপ্তভাবে ঈশ্বর-সমীপে ॥১৬৫॥','чинийа̄ ӣш́вара випра сеи навадвӣпе
рахилена гупта-бха̄ве ӣш́вара-самӣпе',NULL,NULL),('cb.adi.5.166','cb','cb.adi.5','ЧБ Ади 5.166',166,'ভিক্ষা করি’ বিপ্রবর প্রতি স্থানে-স্থানে ।
ঈশ্বরে আসিয়া দেখে প্রতি দিনে-দিনে ॥১৬৬॥','бхикш̣а кари’ випра-вара прати стха̄не-стха̄не
ӣш́вара а̄сийа̄ декхе прати дине-дине',NULL,NULL),('cb.adi.5.167','cb','cb.adi.5','ЧБ Ади 5.167',167,'বেদ-গোপ্য এ-সকল মহাচিত্র কথা ।
ইহার শ্রবণে কৃষ্ণ মিলয়ে সর্ব্বথা ॥১৬৭॥','веда-гопйа э-сакала маха̄читра катха̄
иха̄ра ш́раван̣е кр̣ш̣н̣а милайе сарватха̄',NULL,NULL),('cb.adi.5.168','cb','cb.adi.5','ЧБ Ади 5.168',168,'আদিখণ্ড কথা—যেন অমৃত-স্রবণ ।
যঁহি শিশুরূপে ক্রীড়া করে নারায়ণ ॥১৬৮॥','а̄ди-кхан̣д̣а-катха̄ — йена амр̣та-сраван̣а
йан̇хи ш́иш́у-рӯпе крӣд̣а̄ каре на̄ра̄йан̣а',NULL,NULL),('cb.adi.5.169','cb','cb.adi.5','ЧБ Ади 5.169',169,'সর্ব্বলোকচূড়ামণি বৈকুণ্ঠ-ঈশ্বর ।
লক্ষ্মীকান্ত, সীতাকান্ত শ্রীগৌরসুন্দর ॥১৬৯','сарва-лока-чӯд̣а̄ман̣и ваикун̣т̣ха-ӣш́вара
лакш̣мӣ-ка̄нта, сӣта̄-ка̄нта ш́рӣ-гаурасундара',NULL,NULL),('cb.adi.5.173','cb','cb.adi.5','ЧБ Ади 5.173',173,'শ্রীকৃষ্ণচৈতন্য-নিত্যানন্দচান্দ জান ।
বৃন্দাবনদাস তছু পদযুগে গান ॥১৭৩॥','ш́рӣ кр̣ш̣н̣а-чаитанйа нитйа̄нанда-ча̄нда джа̄на
вр̣нда̄вана да̄са тачху пада-йуге га̄на',NULL,NULL),('cb.adi.6.1','cb','cb.adi.6','ЧБ Ади 6.1',1,'হেনমতে ক্রীড়া করে গৌরাঙ্গ-গোপাল ।
হাতে খড়ি দিবার হইল আসি’ কাল ॥১॥','хена-мате крӣд̣а̄ каре гаура̄н̇га-гопа̄ла
ха̄те кхад̣и дива̄ра хаила а̄си’ ка̄ла',NULL,NULL),('cb.adi.6.2','cb','cb.adi.6','ЧБ Ади 6.2',2,'শুভ-দিনে শুভ-ক্ষণে মিশ্র-পুরন্দর ।
হাতে-খড়ি পুত্ত্রের দিলেন বিপ্রবর ॥২॥','ш́убха-дине ш́убха-кш̣ан̣е миш́ра-пурандара
ха̄те-кхад̣и путрера дилена випра-вара',NULL,NULL),('cb.adi.6.3','cb','cb.adi.6','ЧБ Ади 6.3',3,'কিছু শেষে মিলিয়া সকল বন্ধুগণ ।
কর্ণবেধ করিলেন শ্রীচূড়াকরণ ॥৩॥','кичху ш́еш̣е милийа̄ сакала бандху-ган̣а
карн̣а-ведха карилена ш́рӣ-чӯд̣а̄каран̣а',NULL,NULL),('cb.adi.6.4','cb','cb.adi.6','ЧБ Ади 6.4',4,'দৃষ্টিমাত্র সকল অক্ষর লিখি’ যায় ।
পরম বিস্মিত হইয়া সর্ব্বজনে চায় ॥৪॥','др̣ш̣т̣и-ма̄тра сакала акш̣ара ликхи’ йа̄йа
парама висмита хаийа̄ сарва-джане ча̄йа',NULL,NULL),('cb.adi.6.5','cb','cb.adi.6','ЧБ Ади 6.5',5,'দিন দুই-তিনেতে পঢ়িলা সর্ব্ব ‘ফলা’ ।
নিরন্তর লিখেন কৃষ্ণের নামমালা ॥৫॥','дина дуи-тинете пад̣хила̄ сарва ‘пхала̄’
нирантара ликхена кр̣ш̣н̣ера на̄ма-ма̄ла̄',NULL,NULL),('cb.adi.6.6','cb','cb.adi.6','ЧБ Ади 6.6',6,'রাম, কৃষ্ণ, মুরারি, মুকুন্দ, বনমালী ।
অহর্নিশ লিখেন, পঢ়েন কুতূহলী ॥৬॥','ра̄ма, кр̣ш̣н̣а, мура̄ри, мукунда, ванама̄ли
ахар-ниш́а ликхена, пад̣хена кутӯхалӣ',NULL,NULL),('cb.adi.6.7','cb','cb.adi.6','ЧБ Ади 6.7',7,'শিশুগণ-সঙ্গে পড়ে বৈকুণ্ঠের রায় ।
পরম-সুকৃতি দেখে সর্ব্ব-নদীয়ায় ॥৭॥','ш́иш́у-ган̣а-сан̇ге пад̣е ваикун̣т̣хера-ра̄йа
парама-сукр̣ти декхе сарва-надӣйа̄йа',NULL,NULL),('cb.adi.6.8','cb','cb.adi.6','ЧБ Ади 6.8',8,'কি মাধুরী করি’ প্রভু ‘ক, খ, গ,ঘ’ বোলে ।
তাহা শুনিতেই মাত্র সর্ব্বজীব ভোলে ॥৮॥','ки ма̄дхурӣ кари’ прабху ‘ка, кха, га, гха’ боле
та̄ха̄ ш́унитеи ма̄тра сарва-джӣва бхоле',NULL,NULL),('cb.adi.6.9','cb','cb.adi.6','ЧБ Ади 6.9',9,'অদ্ভুত করেন ক্রীড়া শ্রীগৌরসুন্দর ।
যখন যেচাহে, সেই পরম দুষ্কর ॥৯॥','адбхута карена крӣд̣а̄ ш́рӣ-гаурасундара
йакхана йе ча̄хе, сеи парама душ̣кара',NULL,NULL),('cb.adi.6.10','cb','cb.adi.6','ЧБ Ади 6.10',10,'আকাশে উড়িয়া যায় পক্ষী, তাহাচাহে ।
না পাইলে কান্দিয়া ধূলায় গড়ি’ যায়ে ॥১০॥','а̄ка̄ш́е уд̣ийа̄ йа̄йа пакш̣ӣ, та̄ха̄ ча̄хе
на̄ па̄иле ка̄ндийа̄ дхӯла̄йа гад̣и йа̄йе',NULL,NULL),('cb.adi.6.11','cb','cb.adi.6','ЧБ Ади 6.11',11,'ক্ষণে চাহে আকাশের চন্দ্র-তারাগণ ।
হাত-পাও আছাড়িয়া করয়ে ক্রন্দন ॥১১॥','кш̣ан̣е ча̄хе а̄ка̄ш́ера чандра-та̄ра̄-ган̣а
ха̄та-па̄о а̄чха̄д̣ийа̄ карайе крандана',NULL,NULL),('cb.adi.6.12','cb','cb.adi.6','ЧБ Ади 6.12',12,'সান্ত্বনা করেন সভে করি’ নিজ-কোলে ।
স্থির নহে বিশ্বম্ভর, ‘দেও দেও’ বোলে ॥১২॥
সবে একমাত্র আছে মহা-প্রতিকার ।
হরিনাম শুনিলে না কান্দে প্রভু আর ॥১৩॥
হাতে তালি দিয়া সবে বোলে ‘হরি হরি’ ।
তখন সুস্থির হয় চাঞ্চল্য পাসরি’ ॥১৪॥','са̄нтвана̄ карена сабхе кари’ ниджа-коле
стхира нахе виш́вамбхара, ‘део део’ боле
сабе эка-ма̄тра а̄чхе маха̄-пратика̄ра
хари-на̄ма ш́униле на̄ ка̄нде прабху а̄ра
ха̄те та̄ли дийа̄ сабе боле ‘хари хари’
такхана сустхира хайа ча̄н̃чалйа па̄сари’',NULL,NULL),('cb.adi.6.15','cb','cb.adi.6','ЧБ Ади 6.15',15,'বালকের প্রীত্যে সবে বোলে হরিনাম ।
জগন্নাথগৃহ হৈল শ্রীবৈকুণ্ঠ-ধাম ॥১৫॥','ба̄лакера прӣтйе сабе боле хари-на̄ма
джаганна̄тха-грха хаила ш́рӣ-ваикун̣т̣ха-дха̄ма',NULL,NULL),('cb.adi.6.16','cb','cb.adi.6','ЧБ Ади 6.16',16,'একদিন সবে ‘হরি’ বোলে অনুক্ষণ ।
তথাপিহ প্রভু পুনঃ করেন ক্রন্দন ॥১৬॥','эка-дина сабе ‘хари’ боле анукш̣ан̣а
татха̄пиха прабху пунах̣ карена крандана',NULL,NULL),('cb.adi.6.17','cb','cb.adi.6','ЧБ Ади 6.17',17,'সবেই বোলেন,—“শুন, বাপ রে নিমাই! ।
ভাল করি’ নাচ’,—এই হরিনাম গাই” ॥১৭॥','сабеи болена, — ‘ш́уна, ба̄па ре нима̄и!
бха̄ла кари’ на̄ча’, — эи хари-на̄ма га̄и’',NULL,NULL),('cb.adi.6.18','cb','cb.adi.6','ЧБ Ади 6.18',18,'না শুনে বচন কারো, করয়ে ক্রন্দন ।
সবে বলে,—“বোল, বাপ, কান্দ’ কি কারণ?” ॥১৮॥','на̄ ш́уне вачана ка̄ро, карайе крандана
сабе бале’, — ‘бола, ба̄па, ка̄нда’ ки ка̄ран̣а?’',NULL,NULL),('cb.adi.6.19','cb','cb.adi.6','ЧБ Ади 6.19',19,'সবেই বোলেন,—“বাপ, কি ইচ্ছা তোমার? ।
সেই দ্রব্য আনি’ দিব, না কান্দহ আর” ॥১৯॥','сабеи болена, — ‘ба̄па, ки иччха̄ тома̄ра?
сеи дравйа а̄ни’ диба, на̄ ка̄ндаха а̄ра’',NULL,NULL),('cb.adi.6.20','cb','cb.adi.6','ЧБ Ади 6.20',20,'প্রভু বোলে,—“যদি মোর প্রাণ-রক্ষা চাহ’ ।
তবে ঝাট দুই ব্রাহ্মণের ঘরে যাহ’ ॥২০॥
জগদীশ পণ্ডিত হিরণ্য ভাগবত ।
এই দুইস্থানে আমার আছে অভিমত ॥২১॥
একাদশী-উপবাস আজি সে দোঁহার ।
বিষ্ণু লাগি’ করিয়াছে যত উপহার ॥২২॥
সে সব নৈবেদ্য যদি খাইবারে পাঙ ।
তবে মুঞি সুস্থ হই’ হাঁটিয়া বেড়াঙ” ॥২৩॥','прабху боле, — ‘йади мора пра̄н̣а-ракш̣а̄ ча̄ха’
табе джха̄т̣а дуи бра̄хман̣ера гхаре йа̄ха’
джагадӣш́а пан̣д̣ита хиран̣йа бха̄гавата
эи дуи-стха̄не а̄ма̄ра а̄чхе абхимата
эка̄даш́ӣ-упава̄са а̄джи се дон̇ха̄ра
